var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 30일 런던, 화이트 채플\\n<color=#ffd34c>심야</color>","JPN":"1888年9月30日　ロンドン、ホワイトチャペル\\n<color=#ffd34c>深夜</color>","ENG":"September 30, 1888, London, White Chapel,\\n<color=#ffd34c>Midnight</color>","TWN":"1888年9月30日 倫敦，白教堂 <color=#ffd34c>深夜</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"낙서가 남아있어……. 심야의 살인마 짓이야. 벌써 세번째라고……!","JPN":"落書きが残っている……深夜の殺人鬼の仕業だ。もう3回目だよ……！","ENG":"Another writing was left behind... It's the Midnight Killer's doing. It's already his third victim...!","TWN":"有塗鴉留下……是午夜殺人魔幹的。已經是第三次了……！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"쯧쯧, 그러게 젊은 여자가 밤에 뭐 한다고 돌아다녀? 인과응보야 인과응보.","JPN":"若い女が夜の街を出歩いて何をしてたのやら……自業自得だな。","ENG":"Tsk, tsk. Why would a young woman be out so late? You get what you ask for.","TWN":"嘖嘖，年輕女孩晚上到處亂跑，能有什麼好事？這是報應，報應。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"심야의 살인마는 이능력자만 죽인다면서? 그럼, 이번에도…….","JPN":"深夜の殺人鬼が殺すのは異能力者だけなんだって？　じゃあ、今回も……","ENG":"Doesn't the Midnight Killer only kill Supernaturals? Then, this time...","TWN":"午夜殺人魔只殺超能力者吧？那麼，這次也是……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"거기! 현장을 훼손하지 마세요!","JPN":"そこ！　現場から離れなさい！","ENG":"Hey! Don't damage the scene!","TWN":"喂！不要破壞現場！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"자, 비키세요! 수사에 방해가 됩니다.","JPN":"さあさあ、退いてください。捜査の邪魔です。","ENG":"Hey, get out of the way! You're interfering with the investigation.","TWN":"讓開！不要妨礙調查。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"음? 당신은?","JPN":"ん？　あなたは？","ENG":"Hmm? You are...","TWN":"嗯？你是？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다들 반갑네. 스코틀랜드 야드 여러분.","JPN":"やあ、スコットランドヤードの皆さん。","ENG":"Nice to meet you all, officers of Scotland Yard.","TWN":"大家好啊。蘇格蘭場的各位。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"칙령을 받고 사건을 수사중인 프레드릭 애버라인 경위라고 한다네.","JPN":"勅命がくだり事件を捜査しているフレデリック・アバーライン警部補だ。","ENG":"I am Lieutenant Fredrick Abberline, the one in charge of the case by royal decree.","TWN":"我是奉命調查案件的弗雷德里克·艾伯林警官。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_CAP","text":{"KOREA":"기, 기다리고 있었습니다. 애버라인 경위.","JPN":"お、お待ちしてました。アバーライン警部補。","ENG":"W-we've been waiting for you. Lieutenant Abberline.","TWN":"等，等著你呢，艾伯林警官。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_CAP","text":{"KOREA":"현장은 이쪽입니다, 어서.","JPN":"現場はこちらです。どうぞ。","ENG":"The scene is this way.","TWN":"現場在這裡，快這邊請。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐야? 왜 경감님께서 경위한테 쩔쩔매는 거지?","JPN":"なんだ？　なんで警視が警部補に頭を下げる？","ENG":"Huh? Why is the Captain so intimidated by that Lieutenant?","TWN":"什麼呀？為什麼督察要對一個警官畏畏縮縮的？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"멍청아, 애버라인이라는 이름을 대면 무조건 현장에 들여보내라는 보고 못 들었어?","JPN":"バカ、アバーラインという名前を聞いたら黙って現場に入れろって指示を忘れたのか？","ENG":"You idiot. Weren't you told to let the person named Abberline inspect the scene without asking any questions?","TWN":"笨蛋，沒聽上面說只要聽到艾伯林的名字就一定要讓他進去嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐? 그럼 저 사람이 그…….","JPN":"え？　じゃあ、あの人が……","ENG":"What? Then that's...","TWN":"嗯？所以那個人是……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"사인은 날카로운 금속 흉기에 의한 척살.","JPN":"死因は鋭い金属の凶器による刺殺。","ENG":"The cause of death was a fatal wound with a sharp metal weapon.","TWN":"死因是被鋒利的金屬兇器刺殺。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자상이 많았던 이전 사건들과는 달라. 거의 단칼에 절명했어. 범행을 서두른 모양이군.","JPN":"刺傷が多く残っていた前回の事件とは違う。ほぼ一撃で絶命した。犯行を急いだようだな。","ENG":"The victims from previous cases had numerous stab wounds. But this one died with one strike. The murderer must have been in a hurry.","TWN":"和之前有很多刺傷的情況不同，這次幾乎是一刀斃命。看來兇手行兇時很匆忙。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"훼손된 신체는 좌측 <color=#ffd34c>대퇴부</color>. 아마도 여기가 증표가 새겨진 곳이겠지.","JPN":"損傷部位は左<color=#ffd34c>大腿部</color>。おそらくここに印があったのだろう。","ENG":"The mutilated body part was her left <color=#ffd34c>thigh</color>. It should be where her mark was.","TWN":"被破壞的身體部位是左側<color=#ffd34c>大腿</color>。大概這裡就是存在印記的地方吧。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"Also...","TWN":"還有……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"현장에 남아있는 낙서는…….","JPN":"現場に残っている落書きは……","ENG":"The writing left behind at the scene is...","TWN":"現場留下的塗鴉是……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 역시 그렇군.","JPN":"ああ、やはりそうだな。","ENG":"Right, just as I expected.","TWN":"嗯，果真如此。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이제야 그 의미가 분명해졌어. 그렇다면 다음 희생자는 아마도…….","JPN":"やっと意味がわかってきた。では次の犠牲者は……","ENG":"Now, the meaning is clear. Then the next victim will probably be...","TWN":"現在意義已經明確了。那麼下一個犧牲者可能是……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이건? <color=#ffd34c>유리 조각</color>……?","JPN":"これは？　<color=#ffd34c>ガラスの破片</color>……？","ENG":"This is... a <color=#ffd34c>glass shard</color>...?","TWN":"這是塊<color=#ffd34c>玻璃碎片</color>……？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"경감, 피해자의 옷가지와 신발에 젖은 흙이 묻어 있다네.","JPN":"警視、被害者の衣服と靴に泥がついている。","ENG":"The victim's clothes and shoes have mud on them.","TWN":"督察，受害者的衣物和鞋子上沾有濕泥。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"피해자가 처음 기습을 당한 곳은 여기가 아니야. 범인에게 기습당해 쫓기게 된 거지.","JPN":"被害者が最初に襲われた場所はここではない。犯人に襲われ、逃げてきたのだ。","ENG":"This isn't where the victim was first attacked. I assume that she was chased after being attacked somewhere else.","TWN":"受害者最初遭受襲擊的地方不在這裡。我推測她是被兇手襲擊後逃跑到這附近的。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금이라면 아직 경찰의 추적 범위 내에 범인이 있을 거야. 템즈강 일대를 수색하게.","JPN":"犯人はまだ警察の追跡範囲内にいるはず。テムズ川周辺を捜索してくれ。","ENG":"The culprit should still be within the police's pursuit range. Search the Thames River.","TWN":"現在的話，犯人應該還在警方的追蹤範圍內。請搜查泰晤士河一帶。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 범인을 발견하더라도 절대 자극하지 말게.","JPN":"だが、犯人を見つけても決して刺激してはいけない。","ENG":"However, absolutely do not provoke the culprit even if you find him.","TWN":"但即使是發現了犯人，也絕對不要刺激他。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"최악의 경우, 추가적인 범행이 발생할 가능성도 있으니까.","JPN":"最悪の場合、さらなる犯行を重ねる可能性がある。","ENG":"Worst-case scenario, there is a possibility that the culprit will commit additional crimes.","TWN":"最壞的情況下，有可能會發生額外的犯罪行為。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_CAP","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Understood.","TWN":"我知道了。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"동시에 지금부터 내가 적어준 특징을 가진 이능력자들을 찾아 그 신변을 보호하도록.","JPN":"同時に、今から私が説明する特徴を持つ異能力者を探し出し、身辺を保護するように。","ENG":"Meanwhile, find the Supernaturals with the characteristics I wrote down and protect them.","TWN":"同時，從現在開始，找到具有我所寫特徵的超能力者，並保護他們的安全。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_CAP","text":{"KOREA":"잠시만요. 애버라인.","JPN":"待ってください、アバーライン。","ENG":"Wait, Abberline.","TWN":"等等，艾伯林。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_CAP","text":{"KOREA":"저희 스코틀랜드 야드도 이능력자의 신원을 완벽히 파악하고 있진 못합니다.","JPN":"我々スコットランドヤードも、異能力者全員の身元を完全には把握していません。","ENG":"Even we at Scotland Yard haven't fully identified all the Supernaturals.","TWN":"我們蘇格蘭場也無法完全掌握超能力者的身份。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_CAP","text":{"KOREA":"아시다시피, 이능의 증표는 어느 날 갑자기 나타나는 거니까요.","JPN":"ご存じの通り、異能の印はある日突然現れるものですから。","ENG":"As you know, the mark suddenly appears.","TWN":"如你所知，超能力者的印記是某天突然出現的。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……그건 그렇지.","JPN":"……それはそうだな。","ENG":"...That is true.","TWN":"……那倒是。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다고 해도 중요한 문제야. 경찰이 파악할 수 있는 선에서라도 부탁하겠네.","JPN":"それでも重大な事案だ。警察が把握できる範囲だけでもいい。頼む。","ENG":"Nevertheless, this is an important matter. I'd like to ask you to do whatever the police is capable of.","TWN":"即便如此，這也很重要。請在警方能夠掌握的範圍內，幫忙調查一下吧。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그나저나 예상한 것보다 스완이 너무 늦는군.","JPN":"それにしても、スワンが遅いな。","ENG":"Anyway, Swan is running later than expected.","TWN":"話說回來，史旺比預想的要晚得多……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"슬슬 찾으러 가는 편이…….","JPN":"そろそろ探しに行ったほうが……","ENG":"Perhaps I should go look for her–","TWN":"差不多該去找了……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"공기총!?","JPN":"エアライフル！？","ENG":"An air gun?!","TWN":"空氣槍！?"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"그만하면 됐네, 대령.","JPN":"そこまでにしたまえ、大佐。","ENG":"That's enough, Colonel.","TWN":"夠了，上校。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"오랜만일세. 숙적.","JPN":"久々だな。我が宿敵。","ENG":"Long time no see, my nemesis.","TWN":"好久不見，我的宿敵。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"하지만 이상하군. 자네가 왜 런던에 있지? 분명, 프랑스에 있어야 할 텐데 말이야.","JPN":"だが妙だな。どうして君がロンドンにいる？　確か、フランスにいるはずだろうが。","ENG":"How strange seeing you in London. I heard you were supposed to be in France.","TWN":"但是我很疑惑，你為什麼會在倫敦？你明明應該去了法國啊？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그럼 그렇지.","JPN":"ふふ、そういうことか。","ENG":"Haha. Of, course.","TWN":"呵呵，這才對嘛。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 이번 사건에도 관여하고 있었나?","JPN":"やはりこの事件にも関わっていたのかね？","ENG":"Are you involved in this case as I expect you are?","TWN":"果然這次事件也有你參與。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내가 왜 신분을 숨기고 런던에 있는 지는, 네 놈이 더 잘 알고 있을 텐데?","JPN":"どうして私が正体を隠してロンドンにいるのかは、貴様もよくわかっているはずだ。","ENG":"I'm sure you know better than I do why I'm in London while hiding my identity.","TWN":"我為什麼要隱藏身份待在倫敦，你應該比我更清楚吧？"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티 교수.","JPN":"モリアーティ教授。","ENG":"Professor Moriarty.","TWN":"莫里蒂教授。"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};